4	type QuoteStep = { type: "quote"; policy: { items: unknown[] } };
5	type ClaimStep = { type: "claim"; policy: number; incident: { cause: string; damages: unknown[] } };
6	type Step = QuoteStep | ClaimStep;
7	
8	type Scenario = {
9	  customer: { yearsWithMHPCO: number; priorContracts: number; firstInsurance?: boolean };
10	  steps: Step[];
11	};
12	
13	type ProcessorState = {
14	  scenario: Scenario;
15	  priorContracts: number;
16	  remainingCapByPolicy: Map<number, number>;
17	};
18	
19	const processQuoteStep = (step: QuoteStep, state: ProcessorState): { premium: number } => {
20	  const { premium } = quote({
21	    customer: { ...state.scenario.customer, priorContracts: state.priorContracts },
22	    items: step.policy.items as never,
23	  });
24	  state.priorContracts += 1;
25	  return { premium };
26	};
27	
28	const processClaimStep = (step: ClaimStep, state: ProcessorState): { payout: number; remainingCap: number } => {
29	  const policyIndex = step.policy;
30	  const referenced = state.scenario.steps[policyIndex] as QuoteStep;
31	  const tracked = state.remainingCapByPolicy.get(policyIndex);
32	  const claimInput: { items: unknown[]; remainingCap?: number } = { items: referenced.policy.items };
33	  if (tracked !== undefined) claimInput.remainingCap = tracked;
34	  const { payout, remainingCap } = claim(claimInput as never, step.incident as never);
35	  state.remainingCapByPolicy.set(policyIndex, remainingCap);
36	  return { payout, remainingCap };
37	};
38	
39	const processStep = (step: Step, state: ProcessorState): unknown =>
40	  step.type === "quote" ? processQuoteStep(step, state) : processClaimStep(step, state);
